/* global Office, fetch */

/**
 * commands.js — combined function file (Compass v1.0.0.9).
 *
 * Contains the OnMessageSend handler and Office.actions.associate registration.
 * Per Microsoft's canonical Smart Alerts pattern, the manifest's JSRuntime.Url
 * points at this file directly.
 *
 * v1.0.0.9 change: removed `sendModeOverride: "softBlock"` from event.completed
 * so the manifest's `SendMode="PromptUser"` default takes effect.
 * Result: the soft-block dialog now offers both "Send Anyway" and "Don't send"
 * buttons, aligning with Compass's "coach, don't gatekeep" philosophy.
 */

const FLASK_URL = "https://localhost:5000/check";
const INTERNAL_DOMAIN = "coraaj.com";

Office.onReady();

async function onMessageSendHandler(event) {
  try {
    const recipients = await getAllRecipients();
    const allInternal = recipients.length > 0 && recipients.every(isInternal);

    if (allInternal) {
      console.log("Compass: all recipients internal - skipping check.");
      event.completed({ allowEvent: true });
      return;
    }

    const rawBody = await getDraftBody();
    const { draft, history } = splitDraftAndHistory(rawBody);

    const response = await fetch(FLASK_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: draft, client_email: history })
    });

    if (!response.ok) {
      console.warn("Compass: Flask returned " + response.status + ", allowing send.");
      event.completed({ allowEvent: true });
      return;
    }

    const result = await response.json();
    const status = (result.overall_status || "GREEN").toUpperCase();

    if (status === "GREEN") {
      event.completed({ allowEvent: true });
      return;
    }

    const dialogMessage = buildDialogMessage(status, result);

    // PromptUser mode: dialog shows both "Send Anyway" and "Don't send" buttons.
    // SendMode comes from the manifest's LaunchEvent declaration; we don't override here.
    event.completed({
      allowEvent: false,
      cancelLabel: "Don't send",
      errorMessage: dialogMessage
    });

    console.log("Compass intercept:", {
      status: status,
      redCount: (result.red_flags || []).length,
      amberCount: (result.amber_flags || []).length,
      recipients: recipients
    });
  } catch (err) {
    console.error("Compass handler error:", err);
    event.completed({ allowEvent: true });
  }
}

function getDraftBody() {
  return new Promise((resolve, reject) => {
    Office.context.mailbox.item.body.getAsync(
      Office.CoercionType.Text,
      (asyncResult) => {
        if (asyncResult.status === Office.AsyncResultStatus.Succeeded) {
          resolve(asyncResult.value || "");
        } else {
          reject(new Error("Couldn't read the draft body."));
        }
      }
    );
  });
}

function getAllRecipients() {
  const item = Office.context.mailbox.item;
  const toPromise = recipientFieldAsync(item.to);
  const ccPromise = recipientFieldAsync(item.cc);
  const bccPromise = recipientFieldAsync(item.bcc);

  return Promise.all([toPromise, ccPromise, bccPromise]).then((results) => {
    return results.flat();
  });
}

function recipientFieldAsync(field) {
  return new Promise((resolve) => {
    if (!field) {
      resolve([]);
      return;
    }
    field.getAsync((asyncResult) => {
      if (asyncResult.status === Office.AsyncResultStatus.Succeeded && asyncResult.value) {
        resolve(asyncResult.value.map((r) => (r.emailAddress || "").toLowerCase()));
      } else {
        resolve([]);
      }
    });
  });
}

function isInternal(emailAddress) {
  if (!emailAddress) return false;
  return emailAddress.endsWith("@" + INTERNAL_DOMAIN);
}

function splitDraftAndHistory(rawBody) {
  if (!rawBody) return { draft: "", history: "" };

  const markers = [
    /\n\s*From:\s.+\nSent:/i,
    /\n\s*On .+ wrote:/i,
    /\n\s*On .+,.+ at .+ wrote:/i,
    /\n\s*-----Original Message-----/i,
    /\n\s*________________________________/,
    /\n\s*Sent from my iPhone/i,
    /\nFrom: .+@.+\..+/i
  ];

  let earliest = rawBody.length;
  for (const marker of markers) {
    const match = rawBody.match(marker);
    if (match && match.index < earliest) {
      earliest = match.index;
    }
  }

  return {
    draft: rawBody.substring(0, earliest).trim(),
    history: rawBody.substring(earliest).trim()
  };
}

function buildDialogMessage(status, result) {
  let headline;
  if (status === "RED") {
    headline = "Compass flagged this email before sending.";
  } else {
    headline = "Compass has some suggestions for this email.";
  }

  const topFlag = (result.red_flags && result.red_flags[0])
    || (result.amber_flags && result.amber_flags[0])
    || null;

  const issueLine = topFlag ? "Top issue: " + topFlag.issue : "";
  const hint = "Open the Compass taskpane for full details.";

  return [headline, issueLine, hint].filter(Boolean).join("\n\n");
}

// CRITICAL: Map manifest's FunctionName to this JavaScript function.
// Without this, Outlook can't find the handler and the soft-block dialog won't appear.
Office.actions.associate("onMessageSendHandler", onMessageSendHandler);
